const b         = $input.item.binary || {};
const imageKeys = Object.keys(b).filter(k => b[k].mimeType && b[k].mimeType.startsWith('image/'));
const topic     = ($input.item.json['Tema de la clase'] || '').trim();

if (!imageKeys.length && !topic) {
  throw new Error('Por favor, escribe un tema o sube al menos una captura de pantalla.');
}

return [{
  json: { imageKeys, topic, hasImages: imageKeys.length > 0 },
  binary: $input.item.binary
}];

// Collect Gemini output (handles image and text paths)
let items = [];
try { items = $('Gemini — image analyze').all(); } catch(e) {}
if (!items.length) try { items = $('Gemini — text message').all(); } catch(e) {}
if (!items.length) throw new Error('No Gemini output found.');

let text = items[0].json?.content?.parts?.[0]?.text;
if (!text) throw new Error('Gemini returned no text. Check the uploaded material and try again.');

const pageId = $input.first().json.id;

// Extract TÍTULO line if present (image path)
let newTitle = null;
const titleMatch = text.match(/^TÍTULO:\s*(.+)/m);
if (titleMatch) {
  newTitle = titleMatch[1].trim();
  // Remove that line from the text so it doesn't appear in blocks
  text = text.replace(/^TÍTULO:\s*.+\n?/m, '').trimStart();
}

// Rich text helper — respects Notion's 2000-char limit per text object
function rt(content) {
  const result = [];
  let s = String(content);
  while (s.length > 0) {
    result.push({ type: 'text', text: { content: s.slice(0, 2000) } });
    s = s.slice(2000);
  }
  return result;
}

const blocks = [];
const lines = text.split('\n');
let afterOpenDivider = false;
let skipNextDivider  = false;
let introEnded       = false;

for (const rawLine of lines) {
  const line = rawLine.trim();
  if (!line) continue;

  // ── Divider ───────────────────────────────────────────────────────
  if (/^[—\-]{6,}$/.test(line)) {
    introEnded = true;
    if (skipNextDivider) { skipNextDivider = false; continue; }
    blocks.push({ object: 'block', type: 'divider', divider: {} });
    afterOpenDivider = true;
    continue;
  }

  // ── Section heading (right after opening divider) ─────────────────
  if (afterOpenDivider) {
    introEnded = true;
    blocks.push({ object: 'block', type: 'heading_2',
      heading_2: { rich_text: rt(line), is_toggleable: false } });
    afterOpenDivider = false;
    skipNextDivider  = true;
    continue;
  }

  // ── Callout 💡 Tip ────────────────────────────────────────────────
  if (line.startsWith('💡')) {
    introEnded = true;
    const body = line.replace(/^💡\s*(Tip:)?\s*/u, '').trim();
    blocks.push({ object: 'block', type: 'callout',
      callout: { rich_text: rt('Tip: ' + body),
        icon: { type: 'emoji', emoji: '💡' }, color: 'yellow_background' } });
    continue;
  }

  // ── Callout 📌 Extra ──────────────────────────────────────────────
  if (line.startsWith('📌')) {
    introEnded = true;
    const body = line.replace(/^📌\s*(Extra:)?\s*/u, '').trim();
    blocks.push({ object: 'block', type: 'callout',
      callout: { rich_text: rt('Extra: ' + body),
        icon: { type: 'emoji', emoji: '📌' }, color: 'blue_background' } });
    continue;
  }

  // ── Numbered list item ────────────────────────────────────────────
  if (/^\d+\.\s/.test(line)) {
    introEnded = true;
    blocks.push({ object: 'block', type: 'numbered_list_item',
      numbered_list_item: { rich_text: rt(line.replace(/^\d+\.\s*/, '')) } });
    continue;
  }

  // ── Sub-heading (all-caps, no divider context) ────────────────────
  if (line.length >= 3 && !/[a-záéíóúñü]/.test(line) && /[A-ZÁÉÍÓÚÑ]{2,}/.test(line)) {
    introEnded = true;
    blocks.push({ object: 'block', type: 'heading_3',
      heading_3: { rich_text: rt(line), is_toggleable: false } });
    continue;
  }

  // ── Vocabulary / definition bullet ( → ) ─────────────────────────
  if (line.includes(' → ')) {
    blocks.push({ object: 'block', type: 'bulleted_list_item',
      bulleted_list_item: { rich_text: rt(line) } });
    continue;
  }

  // ── Intro paragraph (before first structural marker) ─────────────
  if (!introEnded) {
    blocks.push({ object: 'block', type: 'quote',
      quote: { rich_text: rt(line) } });
    continue;
  }

  // ── Default: paragraph ────────────────────────────────────────────
  blocks.push({ object: 'block', type: 'paragraph',
    paragraph: { rich_text: rt(line) } });
}

// Batch into 100-block groups (Notion API hard limit per append call)
const BATCH = 100;
const result = [];
for (let i = 0; i < blocks.length; i += BATCH) {
  const isFirst = i === 0;
  const batchNewTitle = isFirst ? newTitle : null;
  // Pre-build the PATCH body here so the HTTP node avoids expression-quote issues
  const titlePatch = batchNewTitle
    ? JSON.stringify({ properties: { title: { title: [{ type: 'text', text: { content: batchNewTitle } }] } } })
    : '{}';
  result.push({
    json: {
      pageId,
      blocks: blocks.slice(i, i + BATCH),
      newTitle: batchNewTitle,
      titlePatch
    }
  });
}
return result.length ? result : [{ json: { pageId, blocks: [], newTitle: null, titlePatch: '{}' } }];
